            aOrbiterB = (aWandererF + RotL64(aCross, 27U)) + 0x7F7BD6BE3284AD02ULL;
            //
            aOrbiterF = (aOrbiterF + aOrbiterI) + 0xA22DF442F683593CULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterF) ^ 0x169EF048503E51FAULL;
            aOrbiterC = RotL64((aOrbiterC * 0x1F69F7ADF6B7B1CFULL), 29U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 0xEF7534F93D27740AULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 0xA0DB7D687A69D562ULL;
