            //
            aOrbiterC = ((aOrbiterC + aOrbiterJ) + 0xB9640ED042140EA5ULL) + aPhaseDOrbiterUpdateSaltD[((aIndex + 10U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0x36E20878C293DAB4ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xF8A2C89F39878EDBULL), 35U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterD) + 0xDD360DACA48AEC54ULL) + aPhaseDOrbiterUpdateSaltA[(((31U - aIndex) + 5U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterJ) ^ 0x26844A3D2FD4492AULL;
