            aOrbiterD = (aOrbiterD ^ aOrbiterB) ^ 0x818695D8675DCFD0ULL;
            aOrbiterD = RotL64((aOrbiterD * 0x087E74CC5F4B892DULL), 39U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterK) + 0x45F308674CAABC78ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 0xC35BEA9BB8EFE9ACULL;
            aOrbiterI = RotL64((aOrbiterI * 0x4813AD854149FC6BULL), 57U);
            //
            aIngress = RotL64(aOrbiterC, 56U) ^ aOrbiterK;
            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterH, 27U));
            aIngress = aIngress + (aOrbiterD ^ RotL64(aOrbiterF, 11U));
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterE, 53U));
