            aOrbiterH = (aOrbiterH + aOrbiterB) + 0xCE27B9054A29496AULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterH) ^ 0x89B2B95DA03B88D6ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x7589E72986C3A443ULL), 53U);
