            aOrbiterG = (aOrbiterG + aOrbiterC) + 0xC4AA3C05DC66A5B0ULL;
            aOrbiterE = ((aOrbiterE ^ aOrbiterG) ^ 0xC07AE247D6BA6B48ULL) ^ aPhaseFOrbiterUpdateSaltC[((aIndex + 18U)) & S_SALT1];
            aOrbiterE = RotL64((aOrbiterE * 0xE7F7F4FA15F7E1F1ULL), 43U);
