            aOrbiterD = ((aOrbiterD ^ aOrbiterK) ^ 0x76523B2AD2877ABEULL) ^ aPhaseBOrbiterUpdateSaltE[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterD = RotL64((aOrbiterD * 0xF90CA502E240BE61ULL), 43U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 0xAA7CCD37C7A3455AULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterD) ^ 0x47594DAEFA74D974ULL) ^ aPhaseBOrbiterUpdateSaltF[((aIndex + 28U)) & S_SALT1];
