            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererH = aWandererH ^ ((RotL64(aScatter, 60U) + aOrbiterD) + RotL64(aOrbiterB, 35U));
            aWandererB = aWandererB + ((((RotL64(aCross, 35U) + aOrbiterA) + RotL64(aOrbiterI, 5U)) + RotL64(aCarry, 3U)) + aPhaseBWandererUpdateSaltE[(((31U - aIndex) + 7U)) & S_SALT1]);
            aWandererJ = aWandererJ ^ ((RotL64(aPrevious, 19U) + RotL64(aOrbiterB, 48U)) + aOrbiterA);
            aWandererG = aWandererG + (((RotL64(aIngress, 3U) + RotL64(aOrbiterJ, 19U)) + aOrbiterF) + RotL64(aCarry, 29U));
            aWandererK = aWandererK ^ ((RotL64(aPrevious, 53U) + aOrbiterK) + RotL64(aOrbiterJ, 11U));
