            aOrbiterC = ((aWandererB + RotL64(aCross, 41U)) + RotL64(aCarry, 5U)) + 0x8F3BC2D2DD9E3314ULL;
            aOrbiterH = (((aWandererF + RotL64(aScatter, 11U)) + RotL64(aCarry, 11U)) + 0xC7CF1CBFBAC45855ULL) + aPhaseBOrbiterAssignSaltA[(((31U - aIndex) + 13U)) & S_SALT1];
