            aOrbiterI = ((aWandererG + RotL64(aIngress, 43U)) + RotL64(aCarry, 23U)) + 0x28206E5CF89EEBF7ULL;
            aOrbiterB = (aWandererE + RotL64(aPrevious, 51U)) + 0xD4878387938C123DULL;
            aOrbiterJ = (aWandererJ + RotL64(aScatter, 37U)) + 0x526141488E4A258FULL;
            aOrbiterK = (aWandererI + RotL64(aCross, 54U)) + 0x7090608D659C707FULL;
            aOrbiterA = (aWandererD + RotL64(aScatter, 27U)) + 0x9D10B10BD4294C35ULL;
            aOrbiterF = ((aWandererC + RotL64(aIngress, 5U)) + 0x11D1AD20DD14109AULL) + aPhaseBOrbiterAssignSaltF[(((31U - aIndex) + 19U)) & S_SALT1];
            //
            aOrbiterE = (aOrbiterE + aOrbiterG) + 0x9C88C32763276C51ULL;
