            aOrbiterJ = RotL64((aOrbiterJ * 0x3037BCE353F349E7ULL), 19U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterC) + 0xE8EC83C867851F5BULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterK) ^ 0x689502112A2846B8ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x1A7B596726517641ULL), 37U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0xDD540E4759047423ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 0xA0E9F65275366FC9ULL;
