            //
            aScatter = (RotL64(aPrevious, 23U) ^ RotL64(aCarry, 60U)) ^ (RotL64(aCross, 47U) + RotL64(aIngress, 35U));
            aScatter = TwistMix64::DiffuseC(aScatter);
            //
            aOrbiterA = (((aWandererC + RotL64(aPrevious, 35U)) + RotL64(aCarry, 29U)) + 0x65131A0E4AFDC5EBULL) + aPhaseGOrbiterAssignSaltD[((aIndex + 11U)) & S_SALT1];
            aOrbiterC = (aWandererA + RotL64(aCross, 21U)) + 0xA8FA494B245ED93DULL;
