            //
            aOrbiterI = (aOrbiterI + aOrbiterD) + 0xEF33D3A761290933ULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterI) ^ 0x37DC4275895F9EEFULL) ^ aPhaseGOrbiterUpdateSaltF[((aIndex + 25U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xA5A3610EC599C1ADULL), 11U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterG) + 0xDB3D2A09A3C75BA3ULL) + aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 28U)) & S_SALT1];
            aOrbiterI = (aOrbiterI ^ aOrbiterF) ^ 0xE6AAA3903518B7B8ULL;
            aOrbiterI = RotL64((aOrbiterI * 0xE4973FA652E0731DULL), 29U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 0x3708E7A5AEF67472ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 0xE041572AA884E779ULL;
            aOrbiterH = RotL64((aOrbiterH * 0xD17D08D2AB12C921ULL), 27U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterE) + 0x5A67D418CC660F95ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 0x543D4D6E69E1EE9CULL;
            aOrbiterB = RotL64((aOrbiterB * 0xA766BB493F5F980BULL), 19U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterA) + 0xE671D6956E9370C9ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterK) ^ 0xDB25F6A373ADF206ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xC98213B1859B2073ULL), 23U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 0x8511BA13DD13F368ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterB) ^ 0x3BCEF7B6CBB88463ULL) ^ aPhaseGOrbiterUpdateSaltA[((aIndex + 27U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 0x0DFC12ACBBE2E29BULL), 3U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterB) + 0x445C6D2869465B21ULL) + aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 22U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0x87F554B8715627B2ULL;
