            //
            aWandererH = aWandererH ^ (((RotL64(aCross, 19U) + RotL64(aOrbiterA, 53U)) + aOrbiterK) + aPhaseGWandererUpdateSaltD[(((31U - aIndex) + 16U)) & S_SALT1]);
            aWandererF = aWandererF + (((RotL64(aScatter, 4U) + RotL64(aOrbiterI, 60U)) + aOrbiterC) + RotL64(aCarry, 47U));
            aWandererC = aWandererC ^ ((RotL64(aIngress, 41U) + RotL64(aOrbiterE, 41U)) + aOrbiterH);
