            aOrbiterJ = RotL64((aOrbiterJ * 0xEB51CBC2578B7A81ULL), 13U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0x3AE04F2B75130AF7ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterB) ^ 0xF503FA8F74F21081ULL) ^ aPhaseHOrbiterUpdateSaltC[((aIndex + 13U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 0xB5015203591C9537ULL), 51U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterI) + 0xF86A87727F79D22CULL) + aPhaseHOrbiterUpdateSaltE[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 0x57D045DBA47BD3BFULL;
            aOrbiterA = RotL64((aOrbiterA * 0xCE714B5AC4C33AD3ULL), 47U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterE) + 0xA3135A15DF1E4578ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterD) ^ 0x69FA143E27CA646AULL;
            aOrbiterF = RotL64((aOrbiterF * 0xD105A5D7694E8F37ULL), 35U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterF) + 0xDD7C5F773D5C51DDULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterI) ^ 0x367D5BBB182BA095ULL) ^ aPhaseHOrbiterUpdateSaltB[((aIndex + 25U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0xA66E693AA819588DULL), 3U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterA) + 0x529034FB501EC071ULL;
